create index if not exists email_messages_user_received_idx  on public.email_messages(user_id, received_at desc);create index if not exists email_messages_user_read_idx  on public.email_messages(user_id, is_read, received_at desc);create index if not exists email_messages_user_direction_idx  on public.email_messages(user_id, direction, received_at desc);create index if not exists email_messages_empresa_user_idx  on public.email_messages(empresa_id, user_id);create index if not exists email_messages_thread_user_idx  on public.email_messages(user_id, provider_thread_id);